#!/usr/bin/env python3 """End-to-end test: stalled provider thread zombie kill auto-triage.""" from __future__ import annotations import json import sys import time from pathlib import Path SCRIPTS = Path(__file__).resolve().parent sys.path.insert(0, str(SCRIPTS)) ERRORS: list = [] OPTIMIZATION_LOG = Path(r"D:\PhronesisVault\Operations\logs\system_optimizations.jsonl") def check(name: str, cond: bool, detail: str = "") -> None: if cond: print(f" PASS {name}") else: ERRORS.append(f"{name}: {detail}") print(f" FAIL {name} {detail}") def main() -> int: print("=== Sovereign Telemetry Monitor Self-Test ===\n") from sovereign_telemetry_monitor import ( OPTIMIZATION_LOG as OPT_LOG, SovereignTelemetryMonitor, get_telemetry_monitor, simulate_stalled_provider_test, ) from external_fleet_manager import FleetManager fm = FleetManager() check("telemetry_registry_block", "telemetry" in fm._registry) monitor = get_telemetry_monitor(reload=True) check("monitor_init", monitor is not None) check("zombie_guard", monitor.zombie_guard is not None) # Provider telemetry record + throttle on spike pid = "test-telemetry-provider" for lat in [0.5, 0.6, 0.55, 0.58, 0.52]: monitor.record_dispatch( loop="routing_context", provider_id=pid, success=True, latency_sec=lat, ttft_sec=lat, ) monitor.record_dispatch( loop="routing_context", provider_id=pid, success=True, latency_sec=5.0, ttft_sec=4.5, ) pt = monitor._get_provider(pid) check("throttle_applied", pt.throttle_penalty > 0, f"penalty={pt.throttle_penalty}") # Blacklist filter in fleet manager (real registry provider) ddg_id = "duckduckgo-instant" ddg_pt = monitor._get_provider(ddg_id) monitor._blacklist_provider( ddg_id, ddg_pt, reason="test_blacklist", loop="test", message=f"Blacklisted {ddg_id} for test", ) fm.reload() listed = [p.get("id") for p in fm.list_providers("context")] check("blacklist_excludes_routing", ddg_id not in listed, str(listed)) ddg_pt.blacklisted_until = None # cleanup for downstream tests # Stalled thread simulation print("\n--- Stalled Provider Simulation ---") sim = simulate_stalled_provider_test() print(json.dumps(sim, indent=2)) check("sim_zombie_detected", bool(sim.get("zombie_events")), str(sim.get("zombie_events"))) check("sim_semaphore_released", sim.get("semaphore_force_released") is True) check("sim_auto_triage", sim.get("provider_blacklisted") is True) check("sim_overall_pass", sim.get("pass") is True) # Optimization log written opt_actions = [] if OPT_LOG.is_file(): for line in OPT_LOG.read_text(encoding="utf-8").strip().splitlines()[-20:]: try: evt = json.loads(line) if evt.get("action") in ("zombie_terminated", "temp_blacklist", "throttle_priority"): opt_actions.append(evt.get("action")) except Exception: pass check("optimization_log_written", len(opt_actions) > 0, str(opt_actions)) # Optimize tick tick = monitor.optimize_tick() check("optimize_tick", "active_tasks" in tick) # Curator integration import opportunistic_fleet_agent as curator check("curator_optimize_tick", hasattr(curator, "optimize_tick")) # Prior tests still pass import test_fleet_procurement print("\n--- Regression: fleet procurement ---") rc = test_fleet_procurement.main() check("procurement_regression", rc == 0, f"exit={rc}") print(f"\n=== Results: {len(ERRORS)} failures ===") if ERRORS: for e in ERRORS: print(f" - {e}") return 1 print("ALL PASS Telemetry layer wired") return 0 if __name__ == "__main__": sys.exit(main())